     1→import { useState } from 'react';
     2→import { Clock, Plus, Search, PoundSterling, Users, CheckCircle, AlertCircle, Edit2, Trash2, X, Calendar } from 'lucide-react';
     3→import { useTimesheets } from '../../hooks/useData';
     4→import { toast } from 'sonner';
     5→
     6→type AnyRow = Record<string, unknown>;
     7→
     8→const STATUS_OPTIONS = ['Pending','Approved','Rejected','Paid'];
     9→const DAY_TYPES = ['Normal','Overtime','Weekend','Bank Holiday'];
    10→
    11→const statusColour: Record<string,string> = {
    12→  'Pending':'bg-yellow-100 text-yellow-800','Approved':'bg-green-100 text-green-800',
    13→  'Rejected':'bg-red-100 text-red-700','Paid':'bg-blue-100 text-blue-800',
    14→};
    15→
    16→const emptyForm = { worker_name:'',project_id:'',week_ending:'',monday:'0',tuesday:'0',wednesday:'0',thursday:'0',friday:'0',saturday:'0',sunday:'0',day_type:'Normal',hourly_rate:'',status:'Pending',notes:'' };
    17→
    18→const DAYS = ['monday','tuesday','wednesday','thursday','friday','saturday','sunday'] as const;
    19→const DAY_LABELS = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
    20→
    21→export function Timesheets() {
    22→  const { useList, useCreate, useUpdate, useDelete } = useTimesheets;
    23→  const { data: raw = [], isLoading } = useList();
    24→  const timesheets = raw as AnyRow[];
    25→  const createMutation = useCreate();
    26→  const updateMutation = useUpdate();
    27→  const deleteMutation = useDelete();
    28→
    29→  const [subTab, setSubTab] = useState<'all'|'pending'|'approved'|'summary'>('all');
    30→  const [search, setSearch] = useState('');
    31→  const [statusFilter, setStatusFilter] = useState('All');
    32→  const [showModal, setShowModal] = useState(false);
    33→  function setTab(key: 'all'|'pending'|'approved'|'summary', filter: string) { setSubTab(key); setStatusFilter(filter); }
    34→  const [editing, setEditing] = useState<AnyRow | null>(null);
    35→  const [form, setForm] = useState({ ...emptyForm });
    36→
    37→  const filtered = timesheets.filter(t => {
    38→    const name = String(t.worker_name??'').toLowerCase();
    39→    const matchSearch = name.includes(search.toLowerCase());
    40→    const matchStatus = statusFilter === 'All' || t.status === statusFilter;
    41→    return matchSearch && matchStatus;
    42→  });
    43→
    44→  function getTotalHours(t: AnyRow) {
    45→    return DAYS.reduce((s,d)=>s+Number(t[d]??0),0);
    46→  }
    47→  function getTotalPay(t: AnyRow) {
    48→    return getTotalHours(t) * Number(t.hourly_rate??0);
    49→  }
    50→
    51→  const totalHours = timesheets.reduce((s,t)=>s+getTotalHours(t),0);
    52→  const totalPayroll = timesheets.reduce((s,t)=>s+getTotalPay(t),0);
    53→  const pendingCount = timesheets.filter(t=>t.status==='Pending').length;
    54→  const approvedCount = timesheets.filter(t=>t.status==='Approved').length;
    55→
    56→  // Summary by worker
    57→  const workerMap = new Map<string, { hours: number; pay: number; sheets: number }>();
    58→  timesheets.filter(t=>t.status==='Approved').forEach(t => {
    59→    const name = String(t.worker_name??'Unknown');
    60→    const h = getTotalHours(t); const p = getTotalPay(t);
    61→    const existing = workerMap.get(name) ?? { hours:0, pay:0, sheets:0 };
    62→    workerMap.set(name, { hours: existing.hours+h, pay: existing.pay+p, sheets: existing.sheets+1 });
    63→  });
    64→  const workerSummary = Array.from(workerMap.entries())
    65→    .map(([name, v]) => ({ name, ...v }))
    66→    .sort((a,b) => b.pay - a.pay);
    67→
    68→  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
    69→  function openEdit(t: AnyRow) {
    70→    setEditing(t);
    71→    setForm({ worker_name:String(t.worker_name??''),project_id:String(t.project_id??''),week_ending:String(t.week_ending??''),monday:String(t.monday??'0'),tuesday:String(t.tuesday??'0'),wednesday:String(t.wednesday??'0'),thursday:String(t.thursday??'0'),friday:String(t.friday??'0'),saturday:String(t.saturday??'0'),sunday:String(t.sunday??'0'),day_type:String(t.day_type??'Normal'),hourly_rate:String(t.hourly_rate??''),status:String(t.status??'Pending'),notes:String(t.notes??'') });
    72→    setShowModal(true);
    73→  }
    74→
    75→  async function handleSubmit(e: React.FormEvent) {
    76→    e.preventDefault();
    77→    const payload = { ...form, monday:Number(form.monday)||0,tuesday:Number(form.tuesday)||0,wednesday:Number(form.wednesday)||0,thursday:Number(form.thursday)||0,friday:Number(form.friday)||0,saturday:Number(form.saturday)||0,sunday:Number(form.sunday)||0,hourly_rate:Number(form.hourly_rate)||0 };
    78→    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Timesheet updated'); }
    79→    else { await createMutation.mutateAsync(payload); toast.success('Timesheet submitted'); }
    80→    setShowModal(false);
    81→  }
    82→
    83→  async function handleDelete(id: string) {
    84→    if (!confirm('Delete this timesheet?')) return;
    85→    await deleteMutation.mutateAsync(id); toast.success('Timesheet deleted');
    86→  }
    87→
    88→  async function approve(t: AnyRow) {
    89→    await updateMutation.mutateAsync({ id:String(t.id), data:{ status:'Approved' } });
    90→    toast.success('Timesheet approved');
    91→  }
    92→
    93→  const formTotalHours = DAYS.reduce((s,d)=>s+Number(form[d]||0),0);
    94→  const formTotalPay = formTotalHours * (Number(form.hourly_rate)||0);
    95→
    96→  return (
    97→    <div className="p-6 space-y-6">
    98→      <div className="flex items-center justify-between">
    99→        <div>
   100→          <h1 className="text-2xl font-bold text-gray-900">Timesheets</h1>
   101→          <p className="text-sm text-gray-500 mt-1">Weekly hours tracking & payroll calculation</p>
   102→        </div>
   103→        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
   104→          <Plus size={16}/><span>Submit Timesheet</span>
   105→        </button>
   106→      </div>
   107→
   108→      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
   109→        {[
   110→          { label:'Total Hours', value:`${totalHours.toFixed(0)}h`, icon:Clock, colour:'text-blue-600', bg:'bg-blue-50' },
   111→          { label:'Total Payroll', value:`£${Math.round(totalPayroll).toLocaleString()}`, icon:PoundSterling, colour:'text-green-600', bg:'bg-green-50' },
   112→          { label:'Pending Approval', value:pendingCount, icon:AlertCircle, colour:pendingCount>0?'text-yellow-600':'text-gray-600', bg:pendingCount>0?'bg-yellow-50':'bg-gray-50' },
   113→          { label:'Approved', value:approvedCount, icon:CheckCircle, colour:'text-green-600', bg:'bg-green-50' },
   114→        ].map(kpi=>(
   115→          <div key={kpi.label} className="bg-white rounded-xl border border-gray-200 p-4">
   116→            <div className="flex items-center gap-3">
   117→              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour}/></div>
   118→              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-gray-900">{kpi.value}</p></div>
   119→            </div>
   120→          </div>
   121→        ))}
   122→      </div>
   123→
   124→      <div className="flex gap-1 border-b border-gray-200">
   125→        {([
   126→          { key:'all'      as const, label:'All Timesheets',   filter:'All',       count:timesheets.length },
   127→          { key:'pending'  as const, label:'Pending Approval', filter:'Pending',   count:pendingCount },
   128→          { key:'approved' as const, label:'Approved',         filter:'Approved',  count:approvedCount },
   129→          { key:'summary'  as const, label:'Payroll Summary',  filter:'Approved',  count:null },
   130→        ]).map(t=>(
   131→          <button key={t.key} onClick={()=>setTab(t.key, t.filter)}
   132→            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-orange-600 text-orange-600':'border-transparent text-gray-500 hover:text-gray-700'}`}>
   133→            {t.label}
   134→            {t.count!==null && <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key==='pending'&&t.count>0?'bg-amber-100 text-amber-700':'bg-gray-100 text-gray-600'}`}>{t.count}</span>}
   135→          </button>
   136→        ))}
   137→      </div>
   138→
   139→      {/* Payroll Summary tab */}
   140→      {subTab==='summary' && (
   141→        <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
   142→          <div className="px-4 py-3 border-b border-gray-200 flex items-center justify-between">
   143→            <h3 className="font-semibold text-gray-900">Approved Payroll Summary</h3>
   144→            <span className="text-sm text-gray-500">£{Math.round(timesheets.filter(t=>t.status==='Approved').reduce((s,t)=>s+getTotalPay(t),0)).toLocaleString()} total approved</span>
   145→          </div>
   146→          {workerSummary.length === 0 ? (
   147→            <div className="text-center py-12 text-gray-400"><Clock size={32} className="mx-auto mb-2 opacity-30"/><p>No approved timesheets yet</p></div>
   148→          ) : (
   149→            <table className="w-full text-sm">
   150→              <thead className="bg-gray-50 border-b border-gray-200">
   151→                <tr>{['Worker','Approved Sheets','Total Hours','Total Pay','Avg Hours/Week','Avg Pay/Week'].map(h=><th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wide">{h}</th>)}</tr>
   152→              </thead>
   153→              <tbody className="divide-y divide-gray-100">
   154→                {workerSummary.map(w=>(
   155→                  <tr key={w.name} className="hover:bg-gray-50">
   156→                    <td className="px-4 py-3">
   157→                      <div className="flex items-center gap-3">
   158→                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-400 to-orange-600 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">
   159→                          {w.name.split(' ').map(n=>n[0]).slice(0,2).join('')}
   160→                        </div>
   161→                        <span className="font-medium text-gray-900">{w.name}</span>
   162→                      </div>
   163→                    </td>
   164→                    <td className="px-4 py-3 text-gray-700">{w.sheets}</td>
   165→                    <td className="px-4 py-3 font-medium text-gray-900">{w.hours}h</td>
   166→                    <td className="px-4 py-3 font-semibold text-green-700">£{Math.round(w.pay).toLocaleString()}</td>
   167→                    <td className="px-4 py-3 text-gray-600">{w.sheets > 0 ? Math.round(w.hours/w.sheets) : 0}h</td>
   168→                    <td className="px-4 py-3 text-gray-600">£{w.sheets > 0 ? Math.round(w.pay/w.sheets).toLocaleString() : 0}</td>
   169→                  </tr>
   170→                ))}
   171→              </tbody>
   172→              <tfoot className="bg-gray-50 border-t border-gray-200">
   173→                <tr>
   174→                  <td className="px-4 py-3 font-semibold text-gray-900">Total</td>
   175→                  <td className="px-4 py-3 font-semibold text-gray-900">{workerSummary.reduce((s,w)=>s+w.sheets,0)}</td>
   176→                  <td className="px-4 py-3 font-semibold text-gray-900">{workerSummary.reduce((s,w)=>s+w.hours,0)}h</td>
   177→                  <td className="px-4 py-3 font-semibold text-green-700">£{Math.round(workerSummary.reduce((s,w)=>s+w.pay,0)).toLocaleString()}</td>
   178→                  <td colSpan={2}/>
   179→                </tr>
   180→              </tfoot>
   181→            </table>
   182→          )}
   183→        </div>
   184→      )}
   185→
   186→      {subTab !== 'summary' && <div className="flex flex-wrap gap-3 items-center bg-white rounded-xl border border-gray-200 p-4">
   187→        <div className="relative flex-1 min-w-48">
   188→          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
   189→          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search worker name…" className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   190→        </div>
   191→        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)} className="text-sm border border-gray-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-orange-500">
   192→          {['All',...STATUS_OPTIONS].map(s=><option key={s}>{s}</option>)}
   193→        </select>
   194→      </div>}
   195→
   196→      {subTab !== 'summary' && (isLoading ? (
   197→        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-600"/></div>
   198→      ) : (
   199→        <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
   200→          <table className="w-full">
   201→            <thead className="bg-gray-50 border-b border-gray-200">
   202→              <tr>{['Worker','Week Ending','M','T','W','T','F','S','S','Total Hrs','Rate','Total Pay','Status',''].map((h,i)=><th key={i} className="px-3 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{h}</th>)}</tr>
   203→            </thead>
   204→            <tbody className="divide-y divide-gray-100">
   205→              {filtered.map(t=>{
   206→                const total = getTotalHours(t);
   207→                const pay = getTotalPay(t);
   208→                return (
   209→                  <tr key={String(t.id)} className="hover:bg-gray-50">
   210→                    <td className="px-3 py-3 font-medium text-gray-900">{String(t.worker_name??'—')}</td>
   211→                    <td className="px-3 py-3 text-gray-600">{String(t.week_ending??'—')}</td>
   212→                    {DAYS.map(d=><td key={d} className="px-3 py-3 text-center text-sm text-gray-600">{Number(t[d]??0)||'—'}</td>)}
   213→                    <td className="px-3 py-3 font-semibold text-gray-900">{total}h</td>
   214→                    <td className="px-3 py-3 text-gray-600">£{Number(t.hourly_rate??0)}/h</td>
   215→                    <td className="px-3 py-3 font-semibold text-green-700">£{Math.round(pay).toLocaleString()}</td>
   216→                    <td className="px-3 py-3"><span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(t.status??'')] ?? 'bg-gray-100 text-gray-700'}`}>{String(t.status??'')}</span></td>
   217→                    <td className="px-3 py-3">
   218→                      <div className="flex items-center gap-1">
   219→                        {t.status==='Pending' && <button onClick={()=>approve(t)} className="p-1.5 text-green-600 hover:bg-green-50 rounded" title="Approve"><CheckCircle size={14}/></button>}
   220→                        <button onClick={()=>openEdit(t)} className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded"><Edit2 size={14}/></button>
   221→                        <button onClick={()=>handleDelete(String(t.id))} className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={14}/></button>
   222→                      </div>
   223→                    </td>
   224→                  </tr>
   225→                );
   226→              })}
   227→            </tbody>
   228→          </table>
   229→          {filtered.length === 0 && <div className="text-center py-16 text-gray-400"><Clock size={40} className="mx-auto mb-3 opacity-30"/><p>No timesheets found</p></div>}
   230→        </div>
   231→      ))}
   232→
   233→      {showModal && (
   234→        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
   235→          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
   236→            <div className="flex items-center justify-between p-6 border-b sticky top-0 bg-white z-10">
   237→              <h2 className="text-lg font-semibold">{editing?'Edit Timesheet':'Submit Timesheet'}</h2>
   238→              <button onClick={()=>setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-lg"><X size={18}/></button>
   239→            </div>
   240→            <form onSubmit={handleSubmit} className="p-6 space-y-4">
   241→              {formTotalHours > 0 && (
   242→                <div className="grid grid-cols-2 gap-3 bg-green-50 rounded-xl p-4 text-sm">
   243→                  <div className="text-center"><p className="text-xs text-gray-500 mb-1">Total Hours</p><p className="font-bold text-gray-900">{formTotalHours}h</p></div>
   244→                  <div className="text-center"><p className="text-xs text-gray-500 mb-1">Total Pay</p><p className="font-bold text-green-700">£{Math.round(formTotalPay).toLocaleString()}</p></div>
   245→                </div>
   246→              )}
   247→              <div className="grid grid-cols-2 gap-4">
   248→                <div>
   249→                  <label className="block text-sm font-medium text-gray-700 mb-1">Worker Name *</label>
   250→                  <input required value={form.worker_name} onChange={e=>setForm(f=>({...f,worker_name:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   251→                </div>
   252→                <div>
   253→                  <label className="block text-sm font-medium text-gray-700 mb-1">Week Ending</label>
   254→                  <input type="date" value={form.week_ending} onChange={e=>setForm(f=>({...f,week_ending:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   255→                </div>
   256→                <div>
   257→                  <label className="block text-sm font-medium text-gray-700 mb-1">Hourly Rate (£)</label>
   258→                  <input type="number" step="0.01" value={form.hourly_rate} onChange={e=>setForm(f=>({...f,hourly_rate:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   259→                </div>
   260→                <div>
   261→                  <label className="block text-sm font-medium text-gray-700 mb-1">Day Type</label>
   262→                  <select value={form.day_type} onChange={e=>setForm(f=>({...f,day_type:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
   263→                    {DAY_TYPES.map(d=><option key={d}>{d}</option>)}
   264→                  </select>
   265→                </div>
   266→              </div>
   267→              <div>
   268→                <label className="block text-sm font-medium text-gray-700 mb-2">Hours Per Day</label>
   269→                <div className="grid grid-cols-7 gap-2">
   270→                  {DAYS.map((d,i)=>(
   271→                    <div key={d} className="text-center">
   272→                      <p className="text-xs text-gray-500 mb-1">{DAY_LABELS[i]}</p>
   273→                      <input type="number" min="0" max="24" step="0.5" value={form[d]} onChange={e=>setForm(f=>({...f,[d]:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-2 py-2 text-sm text-center focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   274→                    </div>
   275→                  ))}
   276→                </div>
   277→              </div>
   278→              <div>
   279→                <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
   280→                <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
   281→                  {STATUS_OPTIONS.map(s=><option key={s}>{s}</option>)}
   282→                </select>
   283→              </div>
   284→              <div className="flex gap-3 pt-2">
   285→                <button type="button" onClick={()=>setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-200 rounded-lg text-sm text-gray-700 hover:bg-gray-50">Cancel</button>
   286→                <button type="submit" disabled={createMutation.isPending||updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
   287→                  {editing?'Update Timesheet':'Submit Timesheet'}
   288→                </button>
   289→              </div>
   290→            </form>
   291→          </div>
   292→        </div>
   293→      )}
   294→    </div>
   295→  );
   296→}
