     1→import { useState } from 'react';
     2→import { HardHat, Plus, Search, Phone, Mail, Building2, Star, Edit2, Trash2, X, ChevronDown, ChevronUp, CheckCircle, AlertTriangle, PoundSterling } from 'lucide-react';
     3→import { useSubcontractors } from '../../hooks/useData';
     4→import { toast } from 'sonner';
     5→
     6→type AnyRow = Record<string, unknown>;
     7→
     8→const TRADES = ['Groundworks','Concrete','Structural Steel','Brickwork','Carpentry','Roofing','Cladding','Electrical','Plumbing','HVAC','Plastering','Tiling','Painting','Scaffolding','Demolition','Landscaping'];
     9→const STATUS_OPTIONS = ['Active','On Hold','Blacklisted','Pending Approval'];
    10→const CIS_STATUS = ['Gross','Standard 20%','Higher 30%','Not Registered'];
    11→
    12→const statusColour: Record<string,string> = {
    13→  'Active':'bg-green-100 text-green-800','On Hold':'bg-yellow-100 text-yellow-800',
    14→  'Blacklisted':'bg-red-100 text-red-700','Pending Approval':'bg-blue-100 text-blue-800',
    15→};
    16→
    17→const emptyForm = { company_name:'',contact_name:'',trade:'',email:'',phone:'',address:'',status:'Active',cis_status:'Standard 20%',utr_number:'',insurance_expiry:'',rating:'3',notes:'' };
    18→
    19→export function Subcontractors() {
    20→  const { useList, useCreate, useUpdate, useDelete } = useSubcontractors;
    21→  const { data: raw = [], isLoading } = useList();
    22→  const subs = raw as AnyRow[];
    23→  const createMutation = useCreate();
    24→  const updateMutation = useUpdate();
    25→  const deleteMutation = useDelete();
    26→
    27→  const [subTab, setSubTab] = useState<'directory'|'insurance'|'cis'>('directory');
    28→  const [search, setSearch] = useState('');
    29→  const [tradeFilter, setTradeFilter] = useState('All');
    30→  const [statusFilter, setStatusFilter] = useState('All');
    31→  const [showModal, setShowModal] = useState(false);
