      {subTab === 'cscs' && (
        <div className="space-y-4">
          {cscsAlerts.length === 0 ? (
            <div className="text-center py-16 text-gray-500 bg-gray-900 rounded-xl border border-gray-800">
              <Shield size={40} className="mx-auto mb-3 opacity-30" />
