              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update Member' : 'Add Member'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Clock, Plus, Search, PoundSterling, Users, CheckCircle, AlertCircle, Edit2, Trash2, X, Calendar, XCircle } from 'lucide-react';
import { useTimesheets } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Pending','Submitted','Approved','Rejected','Paid'];

const statusColour: Record<string,string> = {
  'Pending':'bg-gray-700 text-gray-300',
  'Submitted':'bg-blue-500/20 text-blue-400',
  'Approved':'bg-green-500/20 text-green-400',
  'Rejected':'bg-red-500/20 text-red-400',
  'Paid':'bg-purple-500/20 text-purple-400',
};

const emptyForm = {
  workerName:'', projectId:'', weekEnding:'',
  regularHours:'', overtimeHours:'', dayworkHours:'',
  totalPay:'', status:'Pending', cisDeduction:'', notes:''
};

export function Timesheets() {
  const { useList, useCreate, useUpdate, useDelete } = useTimesheets;
  const { data: raw = [], isLoading } = useList();
  const timesheets = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState<'all'|'pending'|'approved'|'summary'>('all');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });

  function getWorkerName(t: AnyRow) { return String(t.workerName ?? t.worker_name ?? ''); }
  function getWeekEnding(t: AnyRow) { return String(t.weekEnding ?? t.week_ending ?? ''); }
  function getTotalPay(t: AnyRow) { return Number(t.totalPay ?? t.total_pay ?? 0); }
  function getCisDeduction(t: AnyRow) { return Number(t.cisDeduction ?? t.cis_deduction ?? 0); }
  function getRegHours(t: AnyRow) { return Number(t.regularHours ?? t.regular_hours ?? 0); }
  function getOTHours(t: AnyRow) { return Number(t.overtimeHours ?? t.overtime_hours ?? 0); }
  function getDWHours(t: AnyRow) { return Number(t.dayworkHours ?? t.daywork_hours ?? 0); }
  function getTotalHours(t: AnyRow) { return getRegHours(t) + getOTHours(t) + getDWHours(t); }

  const setTab = (key: typeof subTab, filter: string) => { setSubTab(key); setStatusFilter(filter); };

  const filtered = timesheets.filter(t => {
    const name = getWorkerName(t).toLowerCase();
    const matchSearch = name.includes(search.toLowerCase());
    let matchStatus = statusFilter === 'All' || t.status === statusFilter;
    if (subTab === 'pending') matchStatus = t.status === 'Submitted' || t.status === 'Pending';
    if (subTab === 'approved') matchStatus = t.status === 'Approved' || t.status === 'Paid';
    return matchSearch && matchStatus;
  });

  const totalPayroll = timesheets.reduce((s,t) => s + getTotalPay(t), 0);
  const pendingCount = timesheets.filter(t => t.status === 'Submitted' || t.status === 'Pending').length;
  const approvedCount = timesheets.filter(t => t.status === 'Approved' || t.status === 'Paid').length;

  const workerMap = new Map<string, { hours: number; pay: number; sheets: number }>();
  timesheets.filter(t => t.status === 'Approved' || t.status === 'Paid').forEach(t => {
    const name = getWorkerName(t) || 'Unknown';
    const h = getTotalHours(t); const p = getTotalPay(t);
    const existing = workerMap.get(name) ?? { hours: 0, pay: 0, sheets: 0 };
    workerMap.set(name, { hours: existing.hours + h, pay: existing.pay + p, sheets: existing.sheets + 1 });
  });
  const workerSummary = Array.from(workerMap.entries()).map(([name, v]) => ({ name, ...v })).sort((a, b) => b.pay - a.pay);

  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
  function openEdit(t: AnyRow) {
    setEditing(t);
    setForm({
      workerName: getWorkerName(t),
      projectId: String(t.projectId ?? t.project_id ?? ''),
      weekEnding: getWeekEnding(t),
      regularHours: String(getRegHours(t)),
      overtimeHours: String(getOTHours(t)),
      dayworkHours: String(getDWHours(t)),
      totalPay: String(getTotalPay(t)),
      status: String(t.status ?? 'Pending'),
      cisDeduction: String(getCisDeduction(t)),
      notes: String(t.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = {
      worker_name: form.workerName,
      project_id: form.projectId,
      week_ending: form.weekEnding,
      regular_hours: Number(form.regularHours) || 0,
      overtime_hours: Number(form.overtimeHours) || 0,
      daywork_hours: Number(form.dayworkHours) || 0,
      total_pay: Number(form.totalPay) || 0,
      status: form.status,
      cis_deduction: Number(form.cisDeduction) || 0,
      notes: form.notes,
    };
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: payload }); toast.success('Timesheet updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Timesheet submitted'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this timesheet?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Timesheet deleted');
  }

  async function approve(t: AnyRow) {
    await updateMutation.mutateAsync({ id: String(t.id), data: { status: 'Approved' } });
    toast.success('Timesheet approved');
  }

  async function reject(t: AnyRow) {
    await updateMutation.mutateAsync({ id: String(t.id), data: { status: 'Rejected' } });
    toast.success('Timesheet rejected');
  }

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Timesheets</h1>
          <p className="text-sm text-gray-400 mt-1">Weekly hours tracking & payroll calculation</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>Submit Timesheet</span>
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Total Payroll', value: `£${Math.round(totalPayroll).toLocaleString()}`, icon: PoundSterling, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Total Sheets', value: timesheets.length, icon: Clock, colour: 'text-blue-400', bg: 'bg-blue-500/10' },
          { label: 'Pending Approval', value: pendingCount, icon: AlertCircle, colour: pendingCount > 0 ? 'text-yellow-400' : 'text-gray-400', bg: pendingCount > 0 ? 'bg-yellow-500/10' : 'bg-gray-800' },
          { label: 'Approved', value: approvedCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'all' as const, label: 'All Timesheets', filter: 'All', count: timesheets.length },
          { key: 'pending' as const, label: 'Pending Approval', filter: 'Pending', count: pendingCount },
          { key: 'approved' as const, label: 'Approved', filter: 'Approved', count: approvedCount },
          { key: 'summary' as const, label: 'Payroll Summary', filter: 'Approved', count: null },
        ]).map(t => (
          <button key={t.key} onClick={() => setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            {t.count !== null && <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key === 'pending' && t.count > 0 ? 'bg-amber-500/20 text-amber-400' : 'bg-gray-800 text-gray-400'}`}>{t.count}</span>}
          </button>
        ))}
      </div>

      {subTab === 'summary' && (
        <div className="bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
          <div className="px-4 py-3 border-b border-gray-800 flex items-center justify-between">
            <h3 className="font-semibold text-white">Approved Payroll Summary</h3>
            <span className="text-sm text-gray-400">£{Math.round(timesheets.filter(t => t.status === 'Approved' || t.status === 'Paid').reduce((s, t) => s + getTotalPay(t), 0)).toLocaleString()} total approved</span>
          </div>
          {workerSummary.length === 0 ? (
            <div className="text-center py-12 text-gray-500"><Clock size={32} className="mx-auto mb-2 opacity-30" /><p>No approved timesheets yet</p></div>
          ) : (
            <table className="w-full text-sm">
              <thead className="bg-gray-800/50 border-b border-gray-800">
                <tr>{['Worker', 'Approved Sheets', 'Total Hours', 'Total Pay', 'Avg Hours/Week', 'Avg Pay/Week'].map(h => <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wide">{h}</th>)}</tr>
              </thead>
              <tbody className="divide-y divide-gray-800">
                {workerSummary.map(w => (
                  <tr key={w.name} className="hover:bg-gray-800/50">
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-500 to-orange-600 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">
                          {w.name.split(' ').map(n => n[0]).slice(0, 2).join('')}
                        </div>
                        <span className="font-medium text-white">{w.name}</span>
                      </div>
                    </td>
                    <td className="px-4 py-3 text-gray-300">{w.sheets}</td>
                    <td className="px-4 py-3 font-medium text-white">{w.hours}h</td>
                    <td className="px-4 py-3 font-semibold text-green-400">£{Math.round(w.pay).toLocaleString()}</td>
                    <td className="px-4 py-3 text-gray-400">{w.sheets > 0 ? Math.round(w.hours / w.sheets) : 0}h</td>
                    <td className="px-4 py-3 text-gray-400">£{w.sheets > 0 ? Math.round(w.pay / w.sheets).toLocaleString() : 0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}

      {subTab !== 'summary' && (
        <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
          <div className="relative flex-1 min-w-48">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
            <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search worker name…" className={inputCls + ' pl-9'} />
          </div>
          <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
            {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
          </select>
        </div>
      )}

      {subTab !== 'summary' && (isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-800/50 border-b border-gray-800">
              <tr>{['Worker', 'Week Ending', 'Reg Hours', 'OT Hours', 'Daywork', 'Total Hrs', 'Total Pay', 'CIS Ded.', 'Status', ''].map((h, i) => <th key={i} className="px-3 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{h}</th>)}</tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {filtered.map(t => {
                const totalHrs = getTotalHours(t);
                const pay = getTotalPay(t);
                const cis = getCisDeduction(t);
                return (
                  <tr key={String(t.id)} className="hover:bg-gray-800/50">
                    <td className="px-3 py-3 font-medium text-white">{getWorkerName(t) || '—'}</td>
                    <td className="px-3 py-3 text-gray-400">{getWeekEnding(t) || '—'}</td>
                    <td className="px-3 py-3 text-center text-gray-300">{getRegHours(t) || '—'}</td>
                    <td className="px-3 py-3 text-center text-gray-300">{getOTHours(t) || '—'}</td>
                    <td className="px-3 py-3 text-center text-gray-300">{getDWHours(t) || '—'}</td>
                    <td className="px-3 py-3 font-semibold text-white">{totalHrs}h</td>
                    <td className="px-3 py-3 font-semibold text-green-400">£{Math.round(pay).toLocaleString()}</td>
                    <td className="px-3 py-3 text-red-400">{cis > 0 ? `£${Math.round(cis).toLocaleString()}` : '—'}</td>
                    <td className="px-3 py-3"><span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(t.status ?? '')] ?? 'bg-gray-700 text-gray-300'}`}>{String(t.status ?? '')}</span></td>
                    <td className="px-3 py-3">
                      <div className="flex items-center gap-1">
                        {(t.status === 'Submitted' || t.status === 'Pending') && (
                          <>
                            <button onClick={() => approve(t)} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Approve"><CheckCircle size={14} /></button>
                            <button onClick={() => reject(t)} className="p-1.5 text-red-400 hover:bg-red-500/20 rounded" title="Reject"><XCircle size={14} /></button>
                          </>
                        )}
                        <button onClick={() => openEdit(t)} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                        <button onClick={() => handleDelete(String(t.id))} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><Clock size={40} className="mx-auto mb-3 opacity-30" /><p>No timesheets found</p></div>}
        </div>
      ))}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit Timesheet' : 'Submit Timesheet'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelCls}>Worker Name *</label>
                  <input required value={form.workerName} onChange={e => setForm(f => ({ ...f, workerName: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Project</label>
                  <input value={form.projectId} onChange={e => setForm(f => ({ ...f, projectId: e.target.value }))} placeholder="Project name or ID" className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Week Ending</label>
                  <input type="date" value={form.weekEnding} onChange={e => setForm(f => ({ ...f, weekEnding: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Regular Hours</label>
                  <input type="number" step="0.5" min="0" value={form.regularHours} onChange={e => setForm(f => ({ ...f, regularHours: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Overtime Hours</label>
                  <input type="number" step="0.5" min="0" value={form.overtimeHours} onChange={e => setForm(f => ({ ...f, overtimeHours: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Daywork Hours</label>
                  <input type="number" step="0.5" min="0" value={form.dayworkHours} onChange={e => setForm(f => ({ ...f, dayworkHours: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Total Pay (£)</label>
                  <input type="number" step="0.01" min="0" value={form.totalPay} onChange={e => setForm(f => ({ ...f, totalPay: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>CIS Deduction (£)</label>
                  <input type="number" step="0.01" min="0" value={form.cisDeduction} onChange={e => setForm(f => ({ ...f, cisDeduction: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Notes</label>
                  <input value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} className={inputCls} />
                </div>
              </div>
              {(Number(form.regularHours) + Number(form.overtimeHours) + Number(form.dayworkHours)) > 0 && (
                <div className="grid grid-cols-2 gap-3 bg-gray-800 rounded-xl p-4 text-sm">
                  <div className="text-center"><p className="text-xs text-gray-500 mb-1">Total Hours</p><p className="font-bold text-white">{Number(form.regularHours) + Number(form.overtimeHours) + Number(form.dayworkHours)}h</p></div>
                  <div className="text-center"><p className="text-xs text-gray-500 mb-1">Total Pay</p><p className="font-bold text-green-400">£{Number(form.totalPay) > 0 ? Math.round(Number(form.totalPay)).toLocaleString() : '—'}</p></div>
                </div>
              )}
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update Timesheet' : 'Submit Timesheet'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { HardHat, Plus, Search, Phone, Mail, Building2, Star, Edit2, Trash2, X, ChevronDown, ChevronUp, CheckCircle, AlertTriangle, PoundSterling } from 'lucide-react';
import { useSubcontractors } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const TRADES = ['Groundworks','Concrete','Structural Steel','Brickwork','Carpentry','Roofing','Cladding','Electrical','Plumbing','HVAC','Plastering','Tiling','Painting','Scaffolding','Demolition','Landscaping'];
const STATUS_OPTIONS = ['Active','On Hold','Blacklisted','Pending Approval'];
const CIS_STATUS = ['Gross','Standard 20%','Higher 30%','Not Registered'];

const statusColour: Record<string,string> = {
  'Active':'bg-green-500/20 text-green-400','On Hold':'bg-yellow-500/20 text-yellow-400',
  'Blacklisted':'bg-red-500/20 text-red-400','Pending Approval':'bg-blue-500/20 text-blue-400',
};
const cisColour: Record<string,string> = {
  'Gross':'bg-green-500/20 text-green-400','Standard 20%':'bg-yellow-500/20 text-yellow-400',
  'Higher 30%':'bg-red-500/20 text-red-400','Not Registered':'bg-gray-700 text-gray-400',
};

const emptyForm = { company_name:'',contact_name:'',trade:'',email:'',phone:'',address:'',status:'Active',cis_status:'Standard 20%',utr_number:'',insurance_expiry:'',rams_status:'Not Submitted',rating:'3',notes:'' };

export function Subcontractors() {
  const { useList, useCreate, useUpdate, useDelete } = useSubcontractors;
  const { data: raw = [], isLoading } = useList();
  const subs = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState<'directory'|'insurance'|'cis'>('directory');
  const [search, setSearch] = useState('');
  const [tradeFilter, setTradeFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  const filtered = subs.filter(s => {
    const name = String(s.company_name ?? '').toLowerCase();
    const trade = String(s.trade ?? '').toLowerCase();
    const matchSearch = name.includes(search.toLowerCase()) || trade.includes(search.toLowerCase());
    const matchTrade = tradeFilter === 'All' || s.trade === tradeFilter;
    const matchStatus = statusFilter === 'All' || s.status === statusFilter;
    return matchSearch && matchTrade && matchStatus;
  });

  const activeCount = subs.filter(s => s.status === 'Active').length;
  const insExpiring = subs.filter(s => {
    if (!s.insurance_expiry) return false;
    const diff = (new Date(String(s.insurance_expiry)).getTime() - Date.now()) / 86400000;
    return diff >= 0 && diff <= 30;
  }).length;
  const avgRating = subs.length > 0 ? (subs.reduce((s, sub) => s + Number(sub.rating ?? 0), 0) / subs.length).toFixed(1) : '—';
  const pendingCount = subs.filter(s => s.status === 'Pending Approval').length;

  const insAlerts = subs.filter(s => {
    if (!s.insurance_expiry) return true;
    const diff = (new Date(String(s.insurance_expiry)).getTime() - Date.now()) / 86400000;
    return diff < 60;
  });

  const cisGroups = CIS_STATUS.map(status => ({
    status,
    subs: subs.filter(s => s.cis_status === status),
    count: subs.filter(s => s.cis_status === status).length,
    totalUTR: subs.filter(s => s.cis_status === status && !!s.utr_number).length,
  })).filter(g => g.count > 0);

  const RAMS_STATUS = ['Not Submitted','Submitted','Approved','Expired'];
  const ramsColour: Record<string,string> = {
    'Not Submitted':'bg-gray-700 text-gray-400','Submitted':'bg-blue-500/20 text-blue-400',
    'Approved':'bg-green-500/20 text-green-400','Expired':'bg-red-500/20 text-red-400',
  };

  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
  function openEdit(s: AnyRow) {
    setEditing(s);
    setForm({
      company_name: String(s.company_name ?? ''), contact_name: String(s.contact_name ?? ''),
      trade: String(s.trade ?? ''), email: String(s.email ?? ''), phone: String(s.phone ?? ''),
      address: String(s.address ?? ''), status: String(s.status ?? 'Active'),
      cis_status: String(s.cis_status ?? 'Standard 20%'), utr_number: String(s.utr_number ?? ''),
      insurance_expiry: String(s.insurance_expiry ?? ''),
      rams_status: String(s.rams_status ?? 'Not Submitted'),
      rating: String(s.rating ?? '3'), notes: String(s.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, rating: Number(form.rating) || 3 };
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: payload }); toast.success('Subcontractor updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Subcontractor added'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Remove this subcontractor?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Subcontractor removed');
  }

  const uniqueTrades = ['All', ...Array.from(new Set(subs.map(s => String(s.trade ?? '')).filter(Boolean)))];

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Subcontractors</h1>
          <p className="text-sm text-gray-400 mt-1">Approved supply chain & contractor register</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>Add Subcontractor</span>
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Active Subs', value: activeCount, icon: Building2, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Pending Approval', value: pendingCount, icon: CheckCircle, colour: 'text-blue-400', bg: 'bg-blue-500/10' },
          { label: 'Insurance Expiring', value: insExpiring, icon: AlertTriangle, colour: insExpiring > 0 ? 'text-red-400' : 'text-gray-400', bg: insExpiring > 0 ? 'bg-red-500/10' : 'bg-gray-800' },
          { label: 'Avg Rating', value: `${avgRating}/5`, icon: Star, colour: 'text-yellow-400', bg: 'bg-yellow-500/10' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'directory', label: 'Directory', icon: HardHat, count: subs.length },
          { key: 'insurance', label: 'Insurance Alerts', icon: AlertTriangle, count: insAlerts.length },
          { key: 'cis', label: 'CIS Status', icon: PoundSterling, count: null },
        ] as const).map(t => (
          <button key={t.key} onClick={() => setSubTab(t.key)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            <t.icon size={14} />{t.label}
            {t.count !== null && <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key === 'insurance' && t.count > 0 ? 'bg-red-500/20 text-red-400' : 'bg-gray-800 text-gray-400'}`}>{t.count}</span>}
          </button>
        ))}
      </div>

      {subTab === 'insurance' && (
        <div className="space-y-4">
          {insAlerts.length === 0 ? (
            <div className="text-center py-16 text-gray-500 bg-gray-900 rounded-xl border border-gray-800">
              <CheckCircle size={40} className="mx-auto mb-3 opacity-30 text-green-500" />
              <p className="font-medium text-gray-300">All insurance records up to date</p>
              <p className="text-sm mt-1">No alerts in the next 60 days</p>
            </div>
          ) : (
            <div className="bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
              <div className="px-4 py-3 bg-red-500/10 border-b border-red-500/30 flex items-center gap-2">
                <AlertTriangle size={16} className="text-red-400" />
                <span className="text-sm font-medium text-red-300">{insAlerts.length} subcontractor{insAlerts.length !== 1 ? 's' : ''} require insurance attention</span>
              </div>
              <table className="w-full text-sm">
                <thead className="bg-gray-800/50 border-b border-gray-800">
                  <tr>{['Company', 'Trade', 'Expiry', 'Days Left', 'Action'].map(h => <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wide">{h}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-gray-800">
                  {insAlerts.map(s => {
                    const hasExpiry = !!s.insurance_expiry;
                    const expired = hasExpiry && new Date(String(s.insurance_expiry)).getTime() < Date.now();
                    const daysLeft = hasExpiry ? Math.round((new Date(String(s.insurance_expiry)).getTime() - Date.now()) / 86400000) : null;
                    return (
                      <tr key={String(s.id ?? '')} className="hover:bg-gray-800/50">
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">{String(s.company_name ?? '?').slice(0, 2).toUpperCase()}</div>
                            <div>
                              <p className="font-medium text-white">{String(s.company_name ?? '')}</p>
                              {!!s.contact_name && <p className="text-xs text-gray-500">{String(s.contact_name)}</p>}
                            </div>
                          </div>
                        </td>
                        <td className="px-4 py-3 text-gray-400">{String(s.trade ?? '—')}</td>
                        <td className="px-4 py-3">{hasExpiry ? <span className={expired ? 'text-red-400 font-semibold' : 'text-amber-400'}>{String(s.insurance_expiry)}</span> : <span className="text-red-400 font-medium">Not recorded</span>}</td>
                        <td className="px-4 py-3">
                          {!hasExpiry ? <span className="text-xs bg-gray-700 text-gray-400 px-2 py-0.5 rounded-full">Unknown</span>
                            : expired ? <span className="text-xs bg-red-500/20 text-red-400 px-2 py-0.5 rounded-full">Expired</span>
                              : <span className="text-xs bg-amber-500/20 text-amber-400 px-2 py-0.5 rounded-full">{daysLeft}d left</span>}
                        </td>
                        <td className="px-4 py-3"><button onClick={() => openEdit(s)} className="text-xs px-3 py-1 bg-orange-500/20 text-orange-400 rounded-lg hover:bg-orange-500/30 font-medium">Update</button></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {subTab === 'cis' && (
        <div className="space-y-4">
          {cisGroups.map(group => (
            <div key={group.status} className="bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
              <div className="flex items-center justify-between px-4 py-3 bg-gray-800/50 border-b border-gray-800">
                <div className="flex items-center gap-3">
                  <PoundSterling size={16} className="text-gray-400" />
                  <span className="font-semibold text-white">{group.status}</span>
                  <span className="text-sm text-gray-400">{group.count} contractor{group.count !== 1 ? 's' : ''}</span>
                </div>
                <span className="text-xs text-gray-500">{group.totalUTR}/{group.count} UTR numbers on file</span>
              </div>
              <table className="w-full text-sm">
                <thead className="bg-gray-800/30 border-b border-gray-800">
                  <tr>{['Company', 'Trade', 'UTR Number', 'Contact', 'Status'].map(h => <th key={h} className="text-left px-4 py-2 text-xs font-semibold text-gray-500 uppercase tracking-wide">{h}</th>)}</tr>
                </thead>
                <tbody className="divide-y divide-gray-800">
                  {group.subs.map(s => (
                    <tr key={String(s.id ?? '')} className="hover:bg-gray-800/50">
                      <td className="px-4 py-2.5">
                        <div className="flex items-center gap-2">
                          <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">{String(s.company_name ?? '?').slice(0, 2).toUpperCase()}</div>
                          <span className="font-medium text-white">{String(s.company_name ?? '')}</span>
                        </div>
                      </td>
                      <td className="px-4 py-2.5 text-gray-400">{String(s.trade ?? '—')}</td>
                      <td className="px-4 py-2.5">{s.utr_number ? <span className="font-mono text-sm text-gray-300">{String(s.utr_number)}</span> : <span className="text-red-400 text-xs">Missing</span>}</td>
                      <td className="px-4 py-2.5 text-gray-400">{String(s.contact_name ?? '—')}</td>
                      <td className="px-4 py-2.5"><span className={`text-xs px-2 py-0.5 rounded-full font-medium ${statusColour[String(s.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(s.status ?? '')}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ))}
          {cisGroups.length === 0 && <div className="text-center py-16 text-gray-500 bg-gray-900 rounded-xl border border-gray-800"><PoundSterling size={40} className="mx-auto mb-3 opacity-30" /><p>No CIS data available</p></div>}
        </div>
      )}

      {subTab === 'directory' && (
        <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
          <div className="relative flex-1 min-w-48">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
            <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search company or trade…" className={inputCls + ' pl-9'} />
          </div>
          <select value={tradeFilter} onChange={e => setTradeFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
            {uniqueTrades.map(t => <option key={t}>{t}</option>)}
          </select>
          <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
            {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
          </select>
          <span className="text-sm text-gray-500 ml-auto">{filtered.length} contractors</span>
        </div>
      )}

      {subTab === 'directory' && (isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 divide-y divide-gray-800">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><HardHat size={40} className="mx-auto mb-3 opacity-30" /><p>No subcontractors found</p></div>}
          {filtered.map(s => {
            const id = String(s.id ?? '');
            const isExp = expanded === id;
            const insExpiring30 = (() => { if (!s.insurance_expiry) return false; const d = (new Date(String(s.insurance_expiry)).getTime() - Date.now()) / 86400000; return d >= 0 && d <= 30; })();
            const rating = Number(s.rating ?? 0);
            const ramsStatus = String(s.rams_status ?? 'Not Submitted');
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800/50 cursor-pointer" onClick={() => setExpanded(isExp ? null : id)}>
                  <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-white font-bold text-sm flex-shrink-0">
                    {String(s.company_name ?? '?').slice(0, 2).toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <p className="font-semibold text-white truncate">{String(s.company_name ?? 'Unknown')}</p>
                      {insExpiring30 && <span className="text-xs bg-red-500/20 text-red-400 px-2 py-0.5 rounded-full">Insurance Expiring</span>}
                    </div>
                    <p className="text-sm text-gray-400">{String(s.trade ?? '')} {s.contact_name ? `· ${s.contact_name}` : ''}</p>
                  </div>
                  <div className="hidden md:flex items-center gap-2 flex-wrap">
                    <div className="flex items-center gap-0.5">
                      {[1, 2, 3, 4, 5].map(i => <Star key={i} size={12} className={i <= rating ? 'text-yellow-400 fill-yellow-400' : 'text-gray-600'} />)}
                    </div>
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(s.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(s.status ?? '')}</span>
                    {!!s.cis_status && <span className={`text-xs px-2 py-1 rounded-full font-medium ${cisColour[String(s.cis_status)] ?? 'bg-gray-700 text-gray-400'}`}>{String(s.cis_status)}</span>}
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${ramsColour[ramsStatus] ?? 'bg-gray-700 text-gray-400'}`}>RAMS: {ramsStatus}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <button onClick={e => { e.stopPropagation(); openEdit(s); }} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                    <button onClick={e => { e.stopPropagation(); handleDelete(id); }} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                    {isExp ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>
                </div>
                {isExp && (
                  <div className="px-6 pb-4 bg-gray-800/30 grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-gray-800">
                    {!!s.email && <div className="pt-4"><p className="text-xs text-gray-500 mb-1">Email</p><a href={`mailto:${s.email}`} className="flex items-center gap-1 text-blue-400 hover:underline"><Mail size={12} />{String(s.email)}</a></div>}
                    {!!s.phone && <div className="pt-4"><p className="text-xs text-gray-500 mb-1">Phone</p><a href={`tel:${s.phone}`} className="flex items-center gap-1 text-blue-400 hover:underline"><Phone size={12} />{String(s.phone)}</a></div>}
                    {!!s.utr_number && <div className="pt-4"><p className="text-xs text-gray-500 mb-1">UTR Number</p><p className="font-mono text-gray-300">{String(s.utr_number)}</p></div>}
                    {!!s.insurance_expiry && <div className="pt-4"><p className="text-xs text-gray-500 mb-1">Insurance Expiry</p><p className={insExpiring30 ? 'text-red-400 font-medium' : 'text-gray-300'}>{String(s.insurance_expiry)}</p></div>}
                    {!!s.address && <div className="col-span-2 pt-4"><p className="text-xs text-gray-500 mb-1">Address</p><p className="text-gray-400">{String(s.address)}</p></div>}
                    {!!s.notes && <div className="col-span-2 md:col-span-4 pt-4"><p className="text-xs text-gray-500 mb-1">Notes</p><p className="text-gray-400">{String(s.notes)}</p></div>}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      ))}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit Subcontractor' : 'Add Subcontractor'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className={labelCls}>Company Name *</label>
                  <input required value={form.company_name} onChange={e => setForm(f => ({ ...f, company_name: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Contact Name</label>
                  <input value={form.contact_name} onChange={e => setForm(f => ({ ...f, contact_name: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Trade</label>
                  <select value={form.trade} onChange={e => setForm(f => ({ ...f, trade: e.target.value }))} className={inputCls}>
                    <option value="">Select…</option>{TRADES.map(t => <option key={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Email</label>
                  <input type="email" value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Phone</label>
                  <input value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>CIS Status</label>
                  <select value={form.cis_status} onChange={e => setForm(f => ({ ...f, cis_status: e.target.value }))} className={inputCls}>
                    {CIS_STATUS.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>UTR Number</label>
                  <input value={form.utr_number} onChange={e => setForm(f => ({ ...f, utr_number: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Insurance Expiry</label>
                  <input type="date" value={form.insurance_expiry} onChange={e => setForm(f => ({ ...f, insurance_expiry: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>RAMS Status</label>
                  <select value={form.rams_status} onChange={e => setForm(f => ({ ...f, rams_status: e.target.value }))} className={inputCls}>
                    {RAMS_STATUS.map(r => <option key={r}>{r}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Rating (1–5)</label>
                  <select value={form.rating} onChange={e => setForm(f => ({ ...f, rating: e.target.value }))} className={inputCls}>
                    {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n} Star{n > 1 ? 's' : ''}</option>)}
                  </select>
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Address</label>
                  <input value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} className={inputCls} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Notes</label>
                  <textarea rows={3} value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update Subcontractor' : 'Add Subcontractor'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Shield, Plus, Search, FileCheck, AlertTriangle, Clock, CheckCircle, Edit2, Trash2, X, ChevronDown, ChevronUp, Download } from 'lucide-react';
import { useRAMS } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Draft','Under Review','Approved','Expired','Superseded'];
const ACTIVITY_TYPES = ['Groundworks','Structural Steel','Concrete Works','Roofing','Scaffolding','Electrical','Plumbing','MEWP Operations','Demolition','Excavation','Working at Height','Hot Works','Confined Space'];
const RISK_LEVELS = ['Low','Medium','High','Critical'];

const statusColour: Record<string,string> = {
  'Draft':'bg-gray-700 text-gray-400','Under Review':'bg-yellow-500/20 text-yellow-400',
  'Approved':'bg-green-500/20 text-green-400','Expired':'bg-red-500/20 text-red-400','Superseded':'bg-gray-700 text-gray-500',
};
const riskColour: Record<string,string> = {
  'Low':'bg-green-500/20 text-green-400','Medium':'bg-yellow-500/20 text-yellow-400',
  'High':'bg-orange-500/20 text-orange-400','Critical':'bg-red-500/20 text-red-400',
};

const emptyForm = { title:'',activity_type:'',project_id:'',risk_level:'Medium',status:'Draft',reviewed_by:'',approved_by:'',valid_from:'',valid_until:'',hazards:'',controls:'',ppe_required:'',version:'1',created_by:'',review_date:'',notes:'' };

export function RAMS() {
  const { useList, useCreate, useUpdate, useDelete } = useRAMS;
  const { data: raw = [], isLoading } = useList();
  const rams = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }

  const filtered = rams.filter(r => {
    const title = String(r.title ?? '').toLowerCase();
    const activity = String(r.activity_type ?? r.activityType ?? '').toLowerCase();
    const matchSearch = title.includes(search.toLowerCase()) || activity.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchSearch && matchStatus;
  });

  const approvedCount = rams.filter(r => r.status === 'Approved').length;
  const reviewCount = rams.filter(r => r.status === 'Under Review').length;
  const expiredCount = rams.filter(r => r.status === 'Expired').length;
  const expiringSoon = rams.filter(r => {
    const until = r.valid_until ?? r.validUntil;
    if (!until || r.status !== 'Approved') return false;
    const diff = (new Date(String(until)).getTime() - Date.now()) / 86400000;
    return diff >= 0 && diff <= 30;
  }).length;

  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
  function openEdit(r: AnyRow) {
    setEditing(r);
    setForm({
      title: String(r.title ?? ''),
      activity_type: String(r.activity_type ?? r.activityType ?? ''),
      project_id: String(r.project_id ?? r.projectId ?? ''),
      risk_level: String(r.risk_level ?? r.riskLevel ?? 'Medium'),
      status: String(r.status ?? 'Draft'),
      reviewed_by: String(r.reviewed_by ?? r.reviewedBy ?? ''),
      approved_by: String(r.approved_by ?? r.approvedBy ?? ''),
      valid_from: String(r.valid_from ?? r.validFrom ?? ''),
      valid_until: String(r.valid_until ?? r.validUntil ?? ''),
      hazards: String(r.hazards ?? ''),
      controls: String(r.controls ?? ''),
      ppe_required: String(r.ppe_required ?? r.ppeRequired ?? ''),
      version: String(r.version ?? '1'),
      created_by: String(r.created_by ?? r.createdBy ?? ''),
      review_date: String(r.review_date ?? r.reviewDate ?? ''),
      notes: String(r.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: form }); toast.success('RAMS updated'); }
    else { await createMutation.mutateAsync(form); toast.success('RAMS created'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this RAMS document?')) return;
    await deleteMutation.mutateAsync(id); toast.success('RAMS deleted');
  }

  async function approve(r: AnyRow) {
    await updateMutation.mutateAsync({ id: String(r.id), data: { status: 'Approved' } });
    toast.success('RAMS approved');
  }

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">RAMS</h1>
          <p className="text-sm text-gray-400 mt-1">Risk Assessment & Method Statements</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>New RAMS</span>
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Approved', value: approvedCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Under Review', value: reviewCount, icon: Clock, colour: 'text-yellow-400', bg: 'bg-yellow-500/10' },
          { label: 'Expired', value: expiredCount, icon: AlertTriangle, colour: 'text-red-400', bg: 'bg-red-500/10' },
          { label: 'Expiring Soon', value: expiringSoon, icon: FileCheck, colour: expiringSoon > 0 ? 'text-orange-400' : 'text-gray-400', bg: expiringSoon > 0 ? 'bg-orange-500/10' : 'bg-gray-800' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'all', label: 'All RAMS', filter: 'All', count: rams.length, cls: '' },
          { key: 'review', label: 'Under Review', filter: 'Under Review', count: reviewCount, cls: 'bg-amber-500/20 text-amber-400' },
          { key: 'approved', label: 'Approved', filter: 'Approved', count: approvedCount, cls: 'bg-green-500/20 text-green-400' },
          { key: 'expired', label: 'Expired', filter: 'Expired', count: expiredCount, cls: 'bg-red-500/20 text-red-400' },
        ]).map(t => (
          <button key={t.key} onClick={() => setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.cls || 'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search title or activity…" className={inputCls + ' pl-9'} />
        </div>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
        </select>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 divide-y divide-gray-800">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><Shield size={40} className="mx-auto mb-3 opacity-30" /><p>No RAMS documents found</p></div>}
          {filtered.map(r => {
            const id = String(r.id ?? '');
            const isExp = expanded === id;
            const validUntil = r.valid_until ?? r.validUntil;
            const version = r.version;
            const activityType = r.activity_type ?? r.activityType;
            const riskLevel = r.risk_level ?? r.riskLevel;
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800/50 cursor-pointer" onClick={() => setExpanded(isExp ? null : id)}>
                  <div className={`p-2 rounded-lg flex-shrink-0 ${riskColour[String(riskLevel ?? '')] ? '' : 'bg-gray-800'}`}>
                    <Shield size={20} className={riskColour[String(riskLevel ?? '')]?.split(' ')[1] ?? 'text-gray-400'} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <p className="font-semibold text-white truncate">{String(r.title ?? 'Untitled')}</p>
                      {version && <span className="text-xs bg-gray-700 text-gray-400 px-2 py-0.5 rounded-full">v{version}</span>}
                    </div>
                    <p className="text-sm text-gray-400">{String(activityType ?? '')} {validUntil ? `· Expires ${validUntil}` : ''}</p>
                  </div>
                  <div className="hidden md:flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${riskColour[String(riskLevel ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(riskLevel ?? '')}</span>
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(r.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(r.status ?? '')}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    {r.status === 'Under Review' && <button onClick={e => { e.stopPropagation(); approve(r); }} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Approve"><CheckCircle size={14} /></button>}
                    <button onClick={e => { e.stopPropagation(); openEdit(r); }} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                    <button onClick={e => { e.stopPropagation(); handleDelete(id); }} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                    <button className="p-1.5 text-gray-500 hover:text-gray-300 hover:bg-gray-700 rounded" title="Download"><Download size={14} /></button>
                    {isExp ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>
                </div>
                {isExp && (
                  <div className="px-6 pb-4 bg-gray-800/30 space-y-3 text-sm border-t border-gray-800">
                    {!!(r.hazards) && <div className="pt-3"><p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Hazards Identified</p><p className="text-gray-300 whitespace-pre-wrap">{String(r.hazards)}</p></div>}
                    {!!(r.controls) && <div><p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Control Measures</p><p className="text-gray-300 whitespace-pre-wrap">{String(r.controls)}</p></div>}
                    {!!(r.ppe_required ?? r.ppeRequired) && <div><p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">PPE Required</p><p className="text-gray-300">{String(r.ppe_required ?? r.ppeRequired)}</p></div>}
                    <div className="flex gap-6 flex-wrap pb-2">
                      {!!(r.reviewed_by ?? r.reviewedBy) && <div><p className="text-xs text-gray-500">Reviewed By</p><p className="text-gray-300">{String(r.reviewed_by ?? r.reviewedBy)}</p></div>}
                      {!!(r.approved_by ?? r.approvedBy) && <div><p className="text-xs text-gray-500">Approved By</p><p className="text-gray-300">{String(r.approved_by ?? r.approvedBy)}</p></div>}
                      {!!(r.created_by ?? r.createdBy) && <div><p className="text-xs text-gray-500">Created By</p><p className="text-gray-300">{String(r.created_by ?? r.createdBy)}</p></div>}
                      {!!(r.valid_from ?? r.validFrom) && <div><p className="text-xs text-gray-500">Valid From</p><p className="text-gray-300">{String(r.valid_from ?? r.validFrom)}</p></div>}
                      {!!(r.valid_until ?? r.validUntil) && <div><p className="text-xs text-gray-500">Valid Until</p><p className="text-gray-300">{String(r.valid_until ?? r.validUntil)}</p></div>}
                      {!!(r.review_date ?? r.reviewDate) && <div><p className="text-xs text-gray-500">Review Date</p><p className="text-gray-300">{String(r.review_date ?? r.reviewDate)}</p></div>}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit RAMS' : 'New RAMS Document'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className={labelCls}>Document Title *</label>
                  <input required value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Activity Type</label>
                  <select value={form.activity_type} onChange={e => setForm(f => ({ ...f, activity_type: e.target.value }))} className={inputCls}>
                    <option value="">Select…</option>{ACTIVITY_TYPES.map(a => <option key={a}>{a}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Risk Level</label>
                  <select value={form.risk_level} onChange={e => setForm(f => ({ ...f, risk_level: e.target.value }))} className={inputCls}>
                    {RISK_LEVELS.map(r => <option key={r}>{r}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Version</label>
                  <input value={form.version} onChange={e => setForm(f => ({ ...f, version: e.target.value }))} placeholder="e.g. 1.0" className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Created By</label>
                  <input value={form.created_by} onChange={e => setForm(f => ({ ...f, created_by: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Review Date</label>
                  <input type="date" value={form.review_date} onChange={e => setForm(f => ({ ...f, review_date: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Reviewed By</label>
                  <input value={form.reviewed_by} onChange={e => setForm(f => ({ ...f, reviewed_by: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Approved By</label>
                  <input value={form.approved_by} onChange={e => setForm(f => ({ ...f, approved_by: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Valid From</label>
                  <input type="date" value={form.valid_from} onChange={e => setForm(f => ({ ...f, valid_from: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Valid Until</label>
                  <input type="date" value={form.valid_until} onChange={e => setForm(f => ({ ...f, valid_until: e.target.value }))} className={inputCls} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Hazards Identified</label>
                  <textarea rows={3} value={form.hazards} onChange={e => setForm(f => ({ ...f, hazards: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Control Measures</label>
                  <textarea rows={3} value={form.controls} onChange={e => setForm(f => ({ ...f, controls: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>PPE Required</label>
                  <input value={form.ppe_required} onChange={e => setForm(f => ({ ...f, ppe_required: e.target.value }))} placeholder="e.g. Hard hat, Hi-vis, Safety boots, Gloves" className={inputCls} />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update RAMS' : 'Create RAMS'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { MessageSquare, Plus, Search, Clock, CheckCircle, AlertTriangle, Edit2, Trash2, X, ChevronDown, ChevronUp } from 'lucide-react';
import { useRFIs } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Open','Pending Response','Answered','Closed','Overdue'];
const PRIORITY_OPTIONS = ['Low','Medium','High','Critical'];
const DISCIPLINE_OPTIONS = ['Architecture','Structural','MEP','Civil','Geotechnical','Planning','Other'];

const statusColour: Record<string,string> = {
  'Open':'bg-blue-500/20 text-blue-400','Pending Response':'bg-yellow-500/20 text-yellow-400',
  'Answered':'bg-green-500/20 text-green-400','Closed':'bg-gray-700 text-gray-400','Overdue':'bg-red-500/20 text-red-400',
};
const priorityColour: Record<string,string> = {
  'Low':'bg-green-500/20 text-green-400','Medium':'bg-yellow-500/20 text-yellow-400',
  'High':'bg-orange-500/20 text-orange-400','Critical':'bg-red-500/20 text-red-400',
};

const emptyForm = { rfi_number:'',title:'',question:'',answer:'',discipline:'',priority:'Medium',status:'Open',assigned_to:'',submitted_by:'',project_id:'',due_date:'',notes:'' };

export function RFIs() {
  const { useList, useCreate, useUpdate, useDelete } = useRFIs;
  const { data: raw = [], isLoading } = useList();
  const rfis = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [priorityFilter, setPriorityFilter] = useState('All');
  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  function getField(r: AnyRow, snake: string, camel: string) { return r[camel] ?? r[snake] ?? ''; }

  const filtered = rfis.filter(r => {
    const title = String(getField(r,'title','title')).toLowerCase();
    const num = String(getField(r,'rfi_number','rfiNumber')).toLowerCase();
    const matchSearch = title.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'All' || r.status === statusFilter;
    const matchPriority = priorityFilter === 'All' || r.priority === priorityFilter;
    return matchSearch && matchStatus && matchPriority;
  });

  const openCount = rfis.filter(r => r.status === 'Open').length;
  const overdueCount = rfis.filter(r => r.status === 'Overdue').length;
  const answeredCount = rfis.filter(r => ['Answered','Closed'].includes(String(r.status ?? ''))).length;

  function nextRFINumber() {
    const nums = rfis.map(r => parseInt(String(getField(r,'rfi_number','rfiNumber') || '0').replace(/\D/g,''))).filter(n => !isNaN(n));
    const next = nums.length > 0 ? Math.max(...nums) + 1 : 1;
    return `RFI-${String(next).padStart(3,'0')}`;
  }

  function openCreate() { setEditing(null); setForm({ ...emptyForm, rfi_number: nextRFINumber() }); setShowModal(true); }
  function openEdit(r: AnyRow) {
    setEditing(r);
    setForm({
      rfi_number: String(getField(r,'rfi_number','rfiNumber')),
      title: String(getField(r,'title','title')),
      question: String(getField(r,'question','question')),
      answer: String(getField(r,'answer','answer')),
      discipline: String(getField(r,'discipline','discipline')),
      priority: String(r.priority ?? 'Medium'),
      status: String(r.status ?? 'Open'),
      assigned_to: String(getField(r,'assigned_to','assignedTo')),
      submitted_by: String(getField(r,'submitted_by','submittedBy')),
      project_id: String(getField(r,'project_id','projectId')),
      due_date: String(getField(r,'due_date','dueDate')),
      notes: String(r.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: form }); toast.success('RFI updated'); }
    else { await createMutation.mutateAsync(form); toast.success('RFI created'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this RFI?')) return;
    await deleteMutation.mutateAsync(id); toast.success('RFI deleted');
  }

  async function markAnswered(r: AnyRow) {
    await updateMutation.mutateAsync({ id: String(r.id), data: { status: 'Answered' } });
    toast.success('RFI marked as answered');
  }

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">RFIs</h1>
          <p className="text-sm text-gray-400 mt-1">Requests for Information — design & technical queries</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>New RFI</span>
        </button>
      </div>

      {overdueCount > 0 && (
        <div className="flex items-center gap-3 bg-red-500/10 border border-red-500/30 rounded-xl px-4 py-3">
          <AlertTriangle size={18} className="text-red-400 flex-shrink-0" />
          <p className="text-sm text-red-300"><span className="font-semibold">{overdueCount} overdue RFI{overdueCount > 1 ? 's' : ''}</span> — requiring urgent response.</p>
        </div>
      )}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Open', value: openCount, icon: MessageSquare, colour: 'text-blue-400', bg: 'bg-blue-500/10' },
          { label: 'Overdue', value: overdueCount, icon: AlertTriangle, colour: overdueCount > 0 ? 'text-red-400' : 'text-gray-400', bg: overdueCount > 0 ? 'bg-red-500/10' : 'bg-gray-800' },
          { label: 'Answered / Closed', value: answeredCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Total Raised', value: rfis.length, icon: Clock, colour: 'text-purple-400', bg: 'bg-purple-500/10' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'all', label: 'All RFIs', filter: 'All', count: rfis.length },
          { key: 'open', label: 'Open', filter: 'Open', count: openCount },
          { key: 'pending', label: 'Pending Response', filter: 'Pending Response', count: rfis.filter(r => r.status === 'Pending Response').length },
          { key: 'answered', label: 'Answered / Closed', filter: 'Answered', count: answeredCount },
          { key: 'overdue', label: 'Overdue', filter: 'Overdue', count: overdueCount },
        ]).map(t => (
          <button key={t.key} onClick={() => setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key === 'overdue' && t.count > 0 ? 'bg-red-500/20 text-red-400' : t.key === 'open' && t.count > 0 ? 'bg-orange-500/20 text-orange-400' : 'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search RFI number or title…" className={inputCls + ' pl-9'} />
        </div>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
        </select>
        <select value={priorityFilter} onChange={e => setPriorityFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...PRIORITY_OPTIONS].map(p => <option key={p}>{p}</option>)}
        </select>
        <span className="text-sm text-gray-500 ml-auto">{filtered.length} RFIs</span>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 divide-y divide-gray-800">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><MessageSquare size={40} className="mx-auto mb-3 opacity-30" /><p>No RFIs found</p></div>}
          {filtered.map(r => {
            const id = String(r.id ?? '');
            const isExp = expanded === id;
            const rfiNumber = String(getField(r,'rfi_number','rfiNumber') || '—');
            const assignedTo = String(getField(r,'assigned_to','assignedTo') || '');
            const dueDate = String(getField(r,'due_date','dueDate') || '');
            const submittedBy = String(getField(r,'submitted_by','submittedBy') || '');
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800/50 cursor-pointer" onClick={() => setExpanded(isExp ? null : id)}>
                  <div className="w-20 flex-shrink-0 text-center">
                    <p className="text-xs font-bold text-orange-400 font-mono">{rfiNumber}</p>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-white truncate">{String(r.title ?? 'Untitled')}</p>
                    <p className="text-sm text-gray-400">{String(r.discipline ?? '')} {assignedTo ? `· Assigned: ${assignedTo}` : ''} {submittedBy ? `· By: ${submittedBy}` : ''} {dueDate ? `· Due: ${dueDate}` : ''}</p>
                  </div>
                  <div className="hidden md:flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${priorityColour[String(r.priority ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(r.priority ?? '')}</span>
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(r.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(r.status ?? '')}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    {r.status === 'Pending Response' && <button onClick={e => { e.stopPropagation(); markAnswered(r); }} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Mark Answered"><CheckCircle size={14} /></button>}
                    <button onClick={e => { e.stopPropagation(); openEdit(r); }} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                    <button onClick={e => { e.stopPropagation(); handleDelete(id); }} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                    {isExp ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>
                </div>
                {isExp && (
                  <div className="px-6 pb-5 bg-gray-800/30 space-y-3 text-sm border-t border-gray-800 pt-3">
                    {!!r.question && <div><p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Question</p><p className="text-gray-300 leading-relaxed">{String(r.question)}</p></div>}
                    {!!r.answer && <div><p className="text-xs font-semibold text-green-500 uppercase tracking-wide mb-1">Answer / Response</p><p className="text-gray-300 leading-relaxed">{String(r.answer)}</p></div>}
                    {!!r.notes && <div><p className="text-xs text-gray-500 mb-1">Notes</p><p className="text-gray-400">{String(r.notes)}</p></div>}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit RFI' : 'New RFI'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelCls}>RFI Number</label>
                  <input value={form.rfi_number} onChange={e => setForm(f => ({ ...f, rfi_number: e.target.value }))} className={inputCls + ' font-mono'} />
                </div>
                <div>
                  <label className={labelCls}>Discipline</label>
                  <select value={form.discipline} onChange={e => setForm(f => ({ ...f, discipline: e.target.value }))} className={inputCls}>
                    <option value="">Select…</option>{DISCIPLINE_OPTIONS.map(d => <option key={d}>{d}</option>)}
                  </select>
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Subject / Title *</label>
                  <input required value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className={inputCls} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Question</label>
                  <textarea rows={3} value={form.question} onChange={e => setForm(f => ({ ...f, question: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
                {editing && (
                  <div className="col-span-2">
                    <label className={labelCls}>Answer / Response</label>
                    <textarea rows={3} value={form.answer} onChange={e => setForm(f => ({ ...f, answer: e.target.value }))} className={inputCls + ' resize-none'} />
                  </div>
                )}
                <div>
                  <label className={labelCls}>Priority</label>
                  <select value={form.priority} onChange={e => setForm(f => ({ ...f, priority: e.target.value }))} className={inputCls}>
                    {PRIORITY_OPTIONS.map(p => <option key={p}>{p}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Submitted By</label>
                  <input value={form.submitted_by} onChange={e => setForm(f => ({ ...f, submitted_by: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Assigned To</label>
                  <input value={form.assigned_to} onChange={e => setForm(f => ({ ...f, assigned_to: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Due Date</label>
                  <input type="date" value={form.due_date} onChange={e => setForm(f => ({ ...f, due_date: e.target.value }))} className={inputCls} />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update RFI' : 'Submit RFI'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { GitBranch, Plus, Search, PoundSterling, CheckCircle, Clock, Edit2, Trash2, X, TrendingUp, AlertTriangle } from 'lucide-react';
import { useChangeOrders } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Draft','Submitted','Under Review','Approved','Rejected','Withdrawn'];
const TYPES = ['Addition','Omission','Substitution','Variation','Provisional Sum'];
const REASONS = ['Client Request','Design Change','Unforeseen Condition','Specification Clarification','Regulatory Requirement','Other'];

const statusColour: Record<string,string> = {
  'Draft':'bg-gray-700 text-gray-400','Submitted':'bg-blue-500/20 text-blue-400',
  'Under Review':'bg-yellow-500/20 text-yellow-400','Approved':'bg-green-500/20 text-green-400',
  'Rejected':'bg-red-500/20 text-red-400','Withdrawn':'bg-gray-700 text-gray-500',
};

const emptyForm = { co_number:'',title:'',type:'Addition',reason:'',value:'',days_extension:'0',status:'Draft',project_id:'',submitted_date:'',approved_date:'',description:'',schedule_impact:'' };

export function ChangeOrders() {
  const { useList, useCreate, useUpdate, useDelete } = useChangeOrders;
  const { data: raw = [], isLoading } = useList();
  const orders = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });

  function getField(o: AnyRow, snake: string, camel: string) { return o[camel] ?? o[snake] ?? ''; }

  const PENDING_STATUSES = ['Draft','Submitted','Under Review'];
  const REJECTED_STATUSES = ['Rejected','Withdrawn'];
  const filtered = orders.filter(o => {
    const title = String(o.title ?? '').toLowerCase();
    const num = String(getField(o,'co_number','coNumber')).toLowerCase();
    const matchSearch = title.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    let matchStatus = statusFilter === 'All' || o.status === statusFilter;
    if (subTab === 'pending') matchStatus = PENDING_STATUSES.includes(String(o.status ?? ''));
    if (subTab === 'rejected') matchStatus = REJECTED_STATUSES.includes(String(o.status ?? ''));
    return matchSearch && matchStatus;
  });

  const totalValue = orders.filter(o => o.status === 'Approved').reduce((s, o) => s + Number(o.value ?? 0), 0);
  const pendingValue = orders.filter(o => ['Submitted','Under Review'].includes(String(o.status ?? ''))).reduce((s, o) => s + Number(o.value ?? 0), 0);
  const approvedCount = orders.filter(o => o.status === 'Approved').length;
  const totalDays = orders.filter(o => o.status === 'Approved').reduce((s, o) => s + Number(o.days_extension ?? o.daysExtension ?? 0), 0);

  function nextCONumber() {
    const nums = orders.map(o => parseInt(String(getField(o,'co_number','coNumber') || '0').replace(/\D/g,''))).filter(n => !isNaN(n));
    const next = nums.length > 0 ? Math.max(...nums) + 1 : 1;
    return `CO-${String(next).padStart(3,'0')}`;
  }

  function openCreate() { setEditing(null); setForm({ ...emptyForm, co_number: nextCONumber() }); setShowModal(true); }
  function openEdit(o: AnyRow) {
    setEditing(o);
    setForm({
      co_number: String(getField(o,'co_number','coNumber')),
      title: String(o.title ?? ''),
      type: String(o.type ?? 'Addition'),
      reason: String(o.reason ?? ''),
      value: String(o.value ?? ''),
      days_extension: String(o.days_extension ?? o.daysExtension ?? '0'),
      status: String(o.status ?? 'Draft'),
      project_id: String(getField(o,'project_id','projectId')),
      submitted_date: String(getField(o,'submitted_date','submittedDate')),
      approved_date: String(getField(o,'approved_date','approvedDate')),
      description: String(o.description ?? ''),
      schedule_impact: String(o.schedule_impact ?? o.scheduleImpact ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, value: Number(form.value) || 0, days_extension: Number(form.days_extension) || 0 };
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: payload }); toast.success('Change order updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Change order created'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this change order?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Change order deleted');
  }

  async function approve(o: AnyRow) {
    await updateMutation.mutateAsync({ id: String(o.id), data: { status: 'Approved', approved_date: new Date().toISOString().slice(0,10) } });
    toast.success('Change order approved');
  }

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Change Orders</h1>
          <p className="text-sm text-gray-400 mt-1">Contract variations, additions & omissions</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>New CO</span>
        </button>
      </div>

      {/* Total value summary card */}
      <div className="bg-gradient-to-r from-orange-600/20 to-orange-500/10 border border-orange-500/30 rounded-xl p-5">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <p className="text-sm text-orange-300 font-medium">Total Contract Variation Value</p>
            <p className="text-3xl font-bold text-white mt-1">£{totalValue.toLocaleString()}</p>
            <p className="text-xs text-gray-400 mt-1">Approved change orders only</p>
          </div>
          <div className="flex gap-6">
            <div className="text-center">
              <p className="text-sm text-yellow-400">£{Math.round(pendingValue).toLocaleString()}</p>
              <p className="text-xs text-gray-500">Pending</p>
            </div>
            <div className="text-center">
              <p className="text-sm text-green-400">{approvedCount}</p>
              <p className="text-xs text-gray-500">Approved COs</p>
            </div>
            <div className="text-center">
              <p className="text-sm text-blue-400">{totalDays}d</p>
              <p className="text-xs text-gray-500">Extension Days</p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Approved Value', value: `£${totalValue.toLocaleString()}`, icon: PoundSterling, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Pending Value', value: `£${pendingValue.toLocaleString()}`, icon: Clock, colour: 'text-yellow-400', bg: 'bg-yellow-500/10' },
          { label: 'Approved COs', value: approvedCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Extension Days', value: totalDays, icon: TrendingUp, colour: 'text-orange-400', bg: 'bg-orange-500/10' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'all', label: 'All COs', filter: 'All', count: orders.length },
          { key: 'pending', label: 'Pending', filter: 'Submitted', count: orders.filter(o => ['Draft','Submitted','Under Review'].includes(String(o.status ?? ''))).length },
          { key: 'approved', label: 'Approved', filter: 'Approved', count: approvedCount },
          { key: 'rejected', label: 'Rejected', filter: 'Rejected', count: orders.filter(o => ['Rejected','Withdrawn'].includes(String(o.status ?? ''))).length },
        ]).map(t => (
          <button key={t.key} onClick={() => { setSubTab(t.key); if (t.key === 'pending') setStatusFilter('All'); else setStatusFilter(t.filter); }}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key === 'approved' ? 'bg-green-500/20 text-green-400' : t.key === 'rejected' ? 'bg-red-500/20 text-red-400' : 'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search CO number or title…" className={inputCls + ' pl-9'} />
        </div>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
        </select>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-800/50 border-b border-gray-800">
              <tr>{['CO #','Title','Type','Amount','Extension','Schedule Impact','Status','Submitted',''].map(h => <th key={h} className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">{h}</th>)}</tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {filtered.map(o => {
                const coNumber = String(getField(o,'co_number','coNumber') || '—');
                const daysExt = Number(o.days_extension ?? o.daysExtension ?? 0);
                const scheduleImpact = String(o.schedule_impact ?? o.scheduleImpact ?? '');
                const submittedDate = String(getField(o,'submitted_date','submittedDate') || '—');
                return (
                  <tr key={String(o.id)} className="hover:bg-gray-800/50">
                    <td className="px-4 py-3 font-mono text-xs font-bold text-orange-400">{coNumber}</td>
                    <td className="px-4 py-3 font-medium text-white max-w-xs truncate">{String(o.title ?? '—')}</td>
                    <td className="px-4 py-3 text-gray-400 text-sm">{String(o.type ?? '—')}</td>
                    <td className="px-4 py-3 font-semibold text-white">£{Number(o.value ?? 0).toLocaleString()}</td>
                    <td className="px-4 py-3 text-gray-400 text-sm">{daysExt > 0 ? `+${daysExt}d` : '—'}</td>
                    <td className="px-4 py-3 text-gray-400 text-sm max-w-xs truncate">{scheduleImpact || '—'}</td>
                    <td className="px-4 py-3"><span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(o.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(o.status ?? '')}</span></td>
                    <td className="px-4 py-3 text-gray-500 text-sm">{submittedDate}</td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        {o.status === 'Under Review' && <button onClick={() => approve(o)} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Approve"><CheckCircle size={14} /></button>}
                        <button onClick={() => openEdit(o)} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                        <button onClick={() => handleDelete(String(o.id))} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><GitBranch size={40} className="mx-auto mb-3 opacity-30" /><p>No change orders found</p></div>}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit Change Order' : 'New Change Order'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelCls}>CO Number</label>
                  <input value={form.co_number} onChange={e => setForm(f => ({ ...f, co_number: e.target.value }))} className={inputCls + ' font-mono'} />
                </div>
                <div>
                  <label className={labelCls}>Type</label>
                  <select value={form.type} onChange={e => setForm(f => ({ ...f, type: e.target.value }))} className={inputCls}>
                    {TYPES.map(t => <option key={t}>{t}</option>)}
                  </select>
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Title *</label>
                  <input required value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Amount (£)</label>
                  <input type="number" value={form.value} onChange={e => setForm(f => ({ ...f, value: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Extension Days</label>
                  <input type="number" value={form.days_extension} onChange={e => setForm(f => ({ ...f, days_extension: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Reason</label>
                  <select value={form.reason} onChange={e => setForm(f => ({ ...f, reason: e.target.value }))} className={inputCls}>
                    <option value="">Select…</option>{REASONS.map(r => <option key={r}>{r}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Submitted Date</label>
                  <input type="date" value={form.submitted_date} onChange={e => setForm(f => ({ ...f, submitted_date: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Schedule Impact</label>
                  <input value={form.schedule_impact} onChange={e => setForm(f => ({ ...f, schedule_impact: e.target.value }))} placeholder="e.g. 2 weeks delay to completion" className={inputCls} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Description</label>
                  <textarea rows={3} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update CO' : 'Create CO'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { ListChecks, Plus, Search, CheckCircle, Clock, AlertTriangle, Edit2, Trash2, X, ChevronDown, ChevronUp } from 'lucide-react';
import { usePunchList } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Open','In Progress','Resolved','Closed','Disputed'];
const PRIORITY_OPTIONS = ['Low','Medium','High','Critical'];
const TRADE_OPTIONS = ['Groundworks','Concrete','Structural Steel','Brickwork','Carpentry','Roofing','Electrical','Plumbing','HVAC','Plastering','Tiling','Painting','Other'];
const CATEGORY_OPTIONS = ['Snagging','Defect','Non-Compliance','Client Request','Safety','Quality','Other'];

const statusColour: Record<string,string> = {
  'Open':'bg-red-500/20 text-red-400','In Progress':'bg-yellow-500/20 text-yellow-400',
  'Resolved':'bg-blue-500/20 text-blue-400','Closed':'bg-green-500/20 text-green-400','Disputed':'bg-purple-500/20 text-purple-400',
};
const priorityColour: Record<string,string> = {
  'Low':'bg-gray-700 text-gray-400','Medium':'bg-yellow-500/20 text-yellow-400',
  'High':'bg-orange-500/20 text-orange-400','Critical':'bg-red-500/20 text-red-400',
};

const emptyForm = { item_number:'',description:'',category:'Snagging',location:'',assigned_to:'',priority:'Medium',status:'Open',due_date:'',project_id:'',trade:'',resolution:'',notes:'' };

export function PunchList() {
  const { useList, useCreate, useUpdate, useDelete } = usePunchList;
  const { data: raw = [], isLoading } = useList();
  const items = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('open');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('Open');
  const [priorityFilter, setPriorityFilter] = useState('All');
  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  function getField(i: AnyRow, snake: string, camel: string) { return i[camel] ?? i[snake] ?? ''; }

  const filtered = items.filter(i => {
    const desc = String(i.description ?? '').toLowerCase();
    const num = String(getField(i,'item_number','itemNumber')).toLowerCase();
    const matchSearch = desc.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    let matchStatus = statusFilter === 'All' || i.status === statusFilter;
    if (subTab === 'closed') matchStatus = ['Resolved','Closed','Disputed'].includes(String(i.status ?? ''));
    const matchPriority = priorityFilter === 'All' || i.priority === priorityFilter;
    return matchSearch && matchStatus && matchPriority;
  });

  const openCount = items.filter(i => i.status === 'Open').length;
  const inProgressCount = items.filter(i => i.status === 'In Progress').length;
  const closedCount = items.filter(i => i.status === 'Closed').length;
  const criticalCount = items.filter(i => i.priority === 'Critical' && !['Closed','Resolved'].includes(String(i.status ?? ''))).length;

  function nextItemNumber() {
    const nums = items.map(i => parseInt(String(getField(i,'item_number','itemNumber') || '0').replace(/\D/g,''))).filter(n => !isNaN(n));
    return `PL-${String(nums.length > 0 ? Math.max(...nums) + 1 : 1).padStart(3,'0')}`;
  }

  function openCreate() { setEditing(null); setForm({ ...emptyForm, item_number: nextItemNumber() }); setShowModal(true); }
  function openEdit(i: AnyRow) {
    setEditing(i);
    setForm({
      item_number: String(getField(i,'item_number','itemNumber')),
      description: String(i.description ?? ''),
      category: String(i.category ?? 'Snagging'),
      location: String(i.location ?? ''),
      assigned_to: String(getField(i,'assigned_to','assignedTo')),
      priority: String(i.priority ?? 'Medium'),
      status: String(i.status ?? 'Open'),
      due_date: String(getField(i,'due_date','dueDate')),
      project_id: String(getField(i,'project_id','projectId')),
      trade: String(i.trade ?? ''),
      resolution: String(i.resolution ?? ''),
      notes: String(i.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: form }); toast.success('Punch list item updated'); }
    else { await createMutation.mutateAsync(form); toast.success('Item added to punch list'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this punch list item?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Item deleted');
  }

  async function markComplete(i: AnyRow) {
    await updateMutation.mutateAsync({ id: String(i.id), data: { status: 'Closed' } });
    toast.success('Item marked complete');
  }

  async function resolve(i: AnyRow) {
    await updateMutation.mutateAsync({ id: String(i.id), data: { status: 'Resolved' } });
    toast.success('Item marked resolved');
  }

  const closureRate = items.length > 0 ? Math.round((closedCount / items.length) * 100) : 0;

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Punch List</h1>
          <p className="text-sm text-gray-400 mt-1">Snagging, defects & closeout items</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>Add Item</span>
        </button>
      </div>

      {criticalCount > 0 && (
        <div className="flex items-center gap-3 bg-red-500/10 border border-red-500/30 rounded-xl px-4 py-3">
          <AlertTriangle size={18} className="text-red-400" />
          <p className="text-sm text-red-300"><span className="font-semibold">{criticalCount} critical item{criticalCount > 1 ? 's' : ''}</span> open — immediate attention required.</p>
        </div>
      )}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Open', value: openCount, icon: AlertTriangle, colour: 'text-red-400', bg: 'bg-red-500/10' },
          { label: 'In Progress', value: inProgressCount, icon: Clock, colour: 'text-yellow-400', bg: 'bg-yellow-500/10' },
          { label: 'Closed', value: closedCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Closure Rate', value: `${closureRate}%`, icon: ListChecks, colour: 'text-blue-400', bg: 'bg-blue-500/10' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'open', label: 'Open', filter: 'Open', count: openCount },
          { key: 'progress', label: 'In Progress', filter: 'In Progress', count: inProgressCount },
          { key: 'closed', label: 'Resolved / Closed', filter: 'Resolved', count: closedCount },
          { key: 'all', label: 'All Items', filter: 'All', count: items.length },
        ]).map(t => (
          <button key={t.key} onClick={() => setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.key === 'open' && t.count > 0 ? 'bg-red-500/20 text-red-400' : 'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search description…" className={inputCls + ' pl-9'} />
        </div>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
        </select>
        <select value={priorityFilter} onChange={e => setPriorityFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...PRIORITY_OPTIONS].map(p => <option key={p}>{p}</option>)}
        </select>
        <span className="text-sm text-gray-500 ml-auto">{filtered.length} items</span>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 divide-y divide-gray-800">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><ListChecks size={40} className="mx-auto mb-3 opacity-30" /><p>No punch list items</p></div>}
          {filtered.map(i => {
            const id = String(i.id ?? '');
            const isExp = expanded === id;
            const itemNumber = String(getField(i,'item_number','itemNumber') || '—');
            const assignedTo = String(getField(i,'assigned_to','assignedTo') || '');
            const dueDate = String(getField(i,'due_date','dueDate') || '');
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800/50 cursor-pointer" onClick={() => setExpanded(isExp ? null : id)}>
                  <div className="w-16 flex-shrink-0">
                    <p className="text-xs font-bold text-orange-400 font-mono">{itemNumber}</p>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-white truncate">{String(i.description ?? 'No description')}</p>
                    <p className="text-sm text-gray-400">{String(i.category ?? '')} {i.location ? `· ${i.location}` : ''} {i.trade ? `· ${i.trade}` : ''} {assignedTo ? `· ${assignedTo}` : ''}</p>
                  </div>
                  <div className="hidden md:flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${priorityColour[String(i.priority ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(i.priority ?? '')}</span>
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(i.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(i.status ?? '')}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    {(i.status === 'Open' || i.status === 'In Progress') && (
                      <button onClick={e => { e.stopPropagation(); markComplete(i); }} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Mark Complete"><CheckCircle size={14} /></button>
                    )}
                    {i.status === 'Open' && (
                      <button onClick={e => { e.stopPropagation(); resolve(i); }} className="p-1.5 text-blue-400 hover:bg-blue-500/20 rounded" title="Resolve"><CheckCircle size={14} /></button>
                    )}
                    <button onClick={e => { e.stopPropagation(); openEdit(i); }} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                    <button onClick={e => { e.stopPropagation(); handleDelete(id); }} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                    {isExp ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>
                </div>
                {isExp && (
                  <div className="px-6 pb-4 bg-gray-800/30 space-y-2 text-sm border-t border-gray-800 pt-3">
                    {!!i.description && <div><p className="text-xs text-gray-500 mb-1">Description</p><p className="text-gray-300">{String(i.description)}</p></div>}
                    {!!i.resolution && <div><p className="text-xs font-semibold text-green-500 mb-1">Resolution</p><p className="text-gray-300">{String(i.resolution)}</p></div>}
                    {!!dueDate && <div><p className="text-xs text-gray-500 mb-1">Due Date</p><p className="text-gray-300">{dueDate}</p></div>}
                    {!!i.notes && <div><p className="text-xs text-gray-500 mb-1">Notes</p><p className="text-gray-400">{String(i.notes)}</p></div>}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-xl max-h-[90vh] overflow-y-auto border border-gray-700">
            <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-semibold text-white">{editing ? 'Edit Item' : 'New Punch List Item'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelCls}>Item Number</label>
                  <input value={form.item_number} onChange={e => setForm(f => ({ ...f, item_number: e.target.value }))} className={inputCls + ' font-mono'} />
                </div>
                <div>
                  <label className={labelCls}>Category</label>
                  <select value={form.category} onChange={e => setForm(f => ({ ...f, category: e.target.value }))} className={inputCls}>
                    {CATEGORY_OPTIONS.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Description *</label>
                  <textarea required rows={3} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
                <div>
                  <label className={labelCls}>Location</label>
                  <input value={form.location} onChange={e => setForm(f => ({ ...f, location: e.target.value }))} placeholder="e.g. Level 2, Room 204" className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Trade</label>
                  <select value={form.trade} onChange={e => setForm(f => ({ ...f, trade: e.target.value }))} className={inputCls}>
                    <option value="">Select…</option>{TRADE_OPTIONS.map(t => <option key={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Assigned To</label>
                  <input value={form.assigned_to} onChange={e => setForm(f => ({ ...f, assigned_to: e.target.value }))} className={inputCls} />
                </div>
                <div>
                  <label className={labelCls}>Priority</label>
                  <select value={form.priority} onChange={e => setForm(f => ({ ...f, priority: e.target.value }))} className={inputCls}>
                    {PRIORITY_OPTIONS.map(p => <option key={p}>{p}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className={inputCls}>
                    {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelCls}>Due Date</label>
                  <input type="date" value={form.due_date} onChange={e => setForm(f => ({ ...f, due_date: e.target.value }))} className={inputCls} />
                </div>
                <div className="col-span-2">
                  <label className={labelCls}>Resolution</label>
                  <textarea rows={2} value={form.resolution} onChange={e => setForm(f => ({ ...f, resolution: e.target.value }))} className={inputCls + ' resize-none'} />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-700 rounded-lg text-sm text-gray-300 hover:bg-gray-800">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update Item' : 'Add Item'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { ClipboardCheck, Plus, Search, CheckCircle, XCircle, Clock, AlertTriangle, Edit2, Trash2, X, ChevronDown, ChevronUp } from 'lucide-react';
import { useInspections } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['Scheduled','In Progress','Passed','Failed','Conditional Pass','Cancelled'];
const INSPECTION_TYPES = ['Structural','Electrical','Plumbing','MEWP Pre-Use','Scaffold','Fire Safety','Health & Safety','Quality Assurance','Environmental','Third Party','Client Walk','Warranty'];

const statusColour: Record<string,string> = {
  'Scheduled':'bg-blue-500/20 text-blue-400','In Progress':'bg-yellow-500/20 text-yellow-400',
  'Passed':'bg-green-500/20 text-green-400','Failed':'bg-red-500/20 text-red-400',
  'Conditional Pass':'bg-orange-500/20 text-orange-400','Cancelled':'bg-gray-700 text-gray-500',
};

function scoreColour(score: number) {
  if (score >= 85) return 'bg-green-500/20 text-green-400';
  if (score >= 70) return 'bg-yellow-500/20 text-yellow-400';
  return 'bg-red-500/20 text-red-400';
}

const emptyForm = { title:'',inspection_type:'Quality Assurance',inspection_date:'',inspector:'',location:'',status:'Scheduled',score:'',findings:'',corrective_actions:'',project_id:'',next_due:'',notes:'' };

export function Inspections() {
  const { useList, useCreate, useUpdate, useDelete } = useInspections;
  const { data: raw = [], isLoading } = useList();
  const inspections = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [typeFilter, setTypeFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  const today = new Date().toISOString().slice(0,10);

  function getField(i: AnyRow, snake: string, camel: string) { return i[camel] ?? i[snake] ?? ''; }

  const filtered = inspections.filter(i => {
    const title = String(i.title ?? '').toLowerCase();
    const matchSearch = title.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'All' || i.status === statusFilter;
    const matchType = typeFilter === 'All' || (i.inspection_type ?? i.inspectionType) === typeFilter;
    return matchSearch && matchStatus && matchType;
  });

  const scheduledCount = inspections.filter(i => i.status === 'Scheduled').length;
  const passedCount = inspections.filter(i => i.status === 'Passed').length;
  const failedCount = inspections.filter(i => i.status === 'Failed').length;
  const dueSoon = inspections.filter(i => {
    const nextDue = i.next_due ?? i.nextDue;
    if (!nextDue) return false;
    const diff = (new Date(String(nextDue)).getTime() - Date.now()) / 86400000;
    return diff >= 0 && diff <= 14;
  }).length;

  function openCreate() { setEditing(null); setForm({ ...emptyForm, inspection_date: today }); setShowModal(true); }
  function openEdit(i: AnyRow) {
    setEditing(i);
    setForm({
      title: String(i.title ?? ''),
      inspection_type: String(i.inspection_type ?? i.inspectionType ?? 'Quality Assurance'),
      inspection_date: String(i.inspection_date ?? i.inspectionDate ?? ''),
      inspector: String(i.inspector ?? ''),
      location: String(i.location ?? ''),
      status: String(i.status ?? 'Scheduled'),
      score: String(i.score ?? ''),
      findings: String(i.findings ?? ''),
      corrective_actions: String(i.corrective_actions ?? i.correctiveActions ?? ''),
      project_id: String(getField(i,'project_id','projectId')),
      next_due: String(i.next_due ?? i.nextDue ?? ''),
      notes: String(i.notes ?? ''),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, score: form.score ? Number(form.score) : null };
    if (editing) { await updateMutation.mutateAsync({ id: String(editing.id), data: payload }); toast.success('Inspection updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Inspection created'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this inspection?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Inspection deleted');
  }

  async function markPassed(i: AnyRow) {
    await updateMutation.mutateAsync({ id: String(i.id), data: { status: 'Passed' } });
    toast.success('Inspection passed');
  }

  async function markFailed(i: AnyRow) {
    await updateMutation.mutateAsync({ id: String(i.id), data: { status: 'Failed' } });
    toast.warning('Inspection marked failed');
  }

  const inputCls = 'w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500';
  const labelCls = 'block text-sm font-medium text-gray-300 mb-1';

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Inspections</h1>
          <p className="text-sm text-gray-400 mt-1">Quality, safety & compliance inspections</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>Schedule Inspection</span>
        </button>
      </div>

      {failedCount > 0 && (
        <div className="flex items-center gap-3 bg-red-500/10 border border-red-500/30 rounded-xl px-4 py-3">
          <XCircle size={18} className="text-red-400" />
          <p className="text-sm text-red-300"><span className="font-semibold">{failedCount} failed inspection{failedCount > 1 ? 's' : ''}</span> — corrective actions required.</p>
        </div>
      )}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Scheduled', value: scheduledCount, icon: Clock, colour: 'text-blue-400', bg: 'bg-blue-500/10' },
          { label: 'Passed', value: passedCount, icon: CheckCircle, colour: 'text-green-400', bg: 'bg-green-500/10' },
          { label: 'Failed', value: failedCount, icon: XCircle, colour: failedCount > 0 ? 'text-red-400' : 'text-gray-400', bg: failedCount > 0 ? 'bg-red-500/10' : 'bg-gray-800' },
          { label: 'Due in 14 Days', value: dueSoon, icon: AlertTriangle, colour: dueSoon > 0 ? 'text-orange-400' : 'text-gray-400', bg: dueSoon > 0 ? 'bg-orange-500/10' : 'bg-gray-800' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-800 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-800">
        {([
          { key: 'all', label: 'All', filter: 'All', count: inspections.length, cls: '' },
          { key: 'scheduled', label: 'Scheduled', filter: 'Scheduled', count: scheduledCount, cls: 'bg-blue-500/20 text-blue-400' },
          { key: 'passed', label: 'Passed', filter: 'Passed', count: passedCount, cls: 'bg-green-500/20 text-green-400' },
          { key: 'failed', label: 'Failed', filter: 'Failed', count: failedCount, cls: 'bg-red-500/20 text-red-400' },
          { key: 'duesoon', label: 'Due Soon', filter: 'Scheduled', count: dueSoon, cls: 'bg-amber-500/20 text-amber-400' },
        ]).map(t => (
          <button key={t.key} onClick={() => setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab === t.key ? 'border-orange-500 text-orange-500' : 'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.cls || 'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-800 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search inspections…" className={inputCls + ' pl-9'} />
        </div>
        <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...INSPECTION_TYPES].map(t => <option key={t}>{t}</option>)}
        </select>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All', ...STATUS_OPTIONS].map(s => <option key={s}>{s}</option>)}
        </select>
        <span className="text-sm text-gray-500 ml-auto">{filtered.length} inspections</span>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" /></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-800 divide-y divide-gray-800">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-500"><ClipboardCheck size={40} className="mx-auto mb-3 opacity-30" /><p>No inspections found</p></div>}
          {filtered.map(i => {
            const id = String(i.id ?? '');
            const isExp = expanded === id;
            const score = Number(i.score ?? 0);
            const inspDate = String(i.inspection_date ?? i.inspectionDate ?? '—');
            const inspType = String(i.inspection_type ?? i.inspectionType ?? '');
            const nextDue = String(i.next_due ?? i.nextDue ?? '');
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800/50 cursor-pointer" onClick={() => setExpanded(isExp ? null : id)}>
                  <div className="w-20 flex-shrink-0 text-center">
                    <p className="text-xs font-bold text-gray-300">{inspDate}</p>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-white truncate">{String(i.title ?? 'Untitled')}</p>
                    <p className="text-sm text-gray-400">{inspType} {i.inspector ? `· ${i.inspector}` : ''} {i.location ? `· ${i.location}` : ''}</p>
                  </div>
                  {score > 0 && (
                    <div className="hidden md:block">
                      <span className={`text-xs px-2 py-1 rounded-full font-bold ${scoreColour(score)}`}>{score}%</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(i.status ?? '')] ?? 'bg-gray-700 text-gray-400'}`}>{String(i.status ?? '')}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    {i.status === 'In Progress' && (
                      <>
                        <button onClick={e => { e.stopPropagation(); markPassed(i); }} className="p-1.5 text-green-400 hover:bg-green-500/20 rounded" title="Pass"><CheckCircle size={14} /></button>
                        <button onClick={e => { e.stopPropagation(); markFailed(i); }} className="p-1.5 text-red-400 hover:bg-red-500/20 rounded" title="Fail"><XCircle size={14} /></button>
                      </>
                    )}
                    <button onClick={e => { e.stopPropagation(); openEdit(i); }} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14} /></button>
                    <button onClick={e => { e.stopPropagation(); handleDelete(id); }} className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14} /></button>
                    {isExp ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>
                </div>
                {isExp && (
